upstreamCalls.query:
query OrdersOrderEditHydrate($id: ID!) {
  order(id: $id) {
    id
    name
    merchantEditable
    cancelledAt
    cancelReason
    displayFinancialStatus
    lineItems(first: 50) {
      nodes {
        id
        title
        quantity
        currentQuantity
        sku
        variant {
          id
          title
          sku
        }
        originalUnitPriceSet {
          shopMoney {
            amount
            currencyCode
          }
        }
      }
    }
  }
}

query OrdersDraftOrderVariantHydrate($id: ID!) {
  productVariant(id: $id) { id title sku taxable price inventoryItem { requiresShipping } product { title } }
}
